class Estudante:
    def __init__(self, nome, notas):
        self.nome = nome
        self.notas = notas
    def media(self):
        return sum(self.notas)/len(self.notas)
    def status(self):
        return 'Aprovado' if self.media() >= 7 else 'Reprovado'

